// ---------------------------------------------------------------------------
// Token type
// ---------------------------------------------------------------------------

/**
 * All colour tokens that make up a theme.
 *
 * Core tokens (19): map 1-to-1 with the standard CSS custom-properties used
 * throughout the app.
 *
 * Area-specific tokens (6): dedicated surface overrides for the sidebar,
 * editor, terminal, and status bar.
 */
export interface ThemeColorTokens {
  // Core tokens
  background: string;
  foreground: string;
  card: string;
  cardForeground: string;
  popover: string;
  popoverForeground: string;
  primary: string;
  primaryForeground: string;
  secondary: string;
  secondaryForeground: string;
  muted: string;
  mutedForeground: string;
  accent: string;
  accentForeground: string;
  destructive: string;
  border: string;
  input: string;
  ring: string;
  /** CSS `color-scheme` value — drives browser chrome (scrollbars, inputs…). */
  colorScheme: "light" | "dark";

  // Area-specific tokens
  sidebarBackground: string;
  sidebarForeground: string;
  editorBackground: string;
  terminalBackground: string;
  statusbarBackground: string;
  statusbarForeground: string;
}

// ---------------------------------------------------------------------------
// Theme definition
// ---------------------------------------------------------------------------

export interface ThemeDefinition {
  readonly id: string;
  readonly label: string;
  readonly description: string;
  readonly colors: ThemeColorTokens;
}

// ---------------------------------------------------------------------------
// CSS-var mapping
// ---------------------------------------------------------------------------

const TOKEN_TO_CSS_VAR: Record<keyof ThemeColorTokens, string> = {
  background: "--background",
  foreground: "--foreground",
  card: "--card",
  cardForeground: "--card-foreground",
  popover: "--popover",
  popoverForeground: "--popover-foreground",
  primary: "--primary",
