import { useCallback, useEffect, useSyncExternalStore } from "react";
import {
  DEFAULT_THEME_ID,
  BUILT_IN_THEMES,
  getThemeById,
  themeColorsToCssVars,
  type ThemeDefinition,
} from "@t3tools/shared/theme";

// ---------------------------------------------------------------------------
// Storage keys
// ---------------------------------------------------------------------------

const STORAGE_KEY = "t3code:color-theme";
const LEGACY_STORAGE_KEY = "t3code:theme";

// ---------------------------------------------------------------------------
// Module-level store (mirrors useSyncExternalStore pattern)
// ---------------------------------------------------------------------------

let listeners: Array<() => void> = [];

function emitChange() {
  for (const listener of listeners) listener();
}

// ---------------------------------------------------------------------------
// Storage helpers
// ---------------------------------------------------------------------------

/**
 * Run once on module load: migrate from the old storage key if needed.
 * Returns the resolved theme id.
 */
function migrateAndGetThemeId(): string {
  const current = localStorage.getItem(STORAGE_KEY);
  if (current && BUILT_IN_THEMES.some((t) => t.id === current)) {
    return current;
  }

  // Migrate from legacy key
  const legacy = localStorage.getItem(LEGACY_STORAGE_KEY);
  if (legacy) {
    const migrated = legacy === "light" ? "t3-light" : "t3-dark";
    localStorage.setItem(STORAGE_KEY, migrated);
    try {
      localStorage.removeItem(LEGACY_STORAGE_KEY);
    } catch {
      // best-effort
    }
    return migrated;
  }

  return DEFAULT_THEME_ID;
}

function getStoredThemeId(): string {
  const raw = localStorage.getItem(STORAGE_KEY);
  if (raw && BUILT_IN_THEMES.some((t) => t.id === raw)) return raw;
  return DEFAULT_THEME_ID;
}

// ---------------------------------------------------------------------------
// DOM application
// ---------------------------------------------------------------------------

function applyTheme(theme: ThemeDefinition, suppressTransitions = false): void {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  const cssVars = themeColorsToCssVars(theme.colors);
  for (const [prop, value] of cssVars) {
    if (prop === "color-scheme") {
      document.documentElement.style.setProperty("color-scheme", value);
    } else {
      document.documentElement.style.setProperty(prop, value);
    }
  }

  document.documentElement.classList.toggle("dark", theme.colors.colorScheme === "dark");

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent a flash of unstyled content
applyTheme(getThemeById(migrateAndGetThemeId()));

// ---------------------------------------------------------------------------
// useSyncExternalStore wiring
// ---------------------------------------------------------------------------

function getSnapshot(): string {
  return getStoredThemeId();
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Sync across tabs
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyTheme(getThemeById(getStoredThemeId()), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

export function useTheme(): {
  readonly themeId: string;
  readonly theme: ThemeDefinition;
  readonly setTheme: (id: string) => void;
} {
  const themeId = useSyncExternalStore(subscribe, getSnapshot);
  const theme = getThemeById(themeId);

  const setTheme = useCallback((nextId: string) => {
    localStorage.setItem(STORAGE_KEY, nextId);
    applyTheme(getThemeById(nextId), true);
    emitChange();
  }, []);

  // Keep DOM in sync on mount/change
  useEffect(() => {
    applyTheme(theme);
  }, [theme]);

  return { themeId, theme, setTheme };
}

