import { BUILT_IN_THEMES } from "@t3tools/shared/theme";
import { useThemeContext } from "./ThemeProvider";

/**
 * Visual theme picker with colour-preview swatches.
 *
 * Renders a responsive grid of theme cards. Each card shows a miniature
 * preview built from the theme's own colour tokens so you can see what the
 * theme looks like before selecting it.
 *
 * Accessibility: wraps the grid in `role="radiogroup"` and marks each card
 * with `role="radio"` / `aria-checked`, matching the keyboard/screen-reader
 * contract of a standard radio group.
 */
export function ThemeSelector() {
  const { themeId, setTheme } = useThemeContext();

  return (
    <div
      role="radiogroup"
      aria-label="Color theme"
      className="grid grid-cols-1 gap-3 sm:grid-cols-3"
    >
      {BUILT_IN_THEMES.map((t) => {
        const selected = themeId === t.id;
        const c = t.colors;

        return (
          <button
            key={t.id}
            type="button"
            role="radio"
            aria-checked={selected}
            className={[
              "flex flex-col gap-2.5 rounded-xl border p-3 text-left transition-colors",
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent",
            ].join(" ")}
            onClick={() => setTheme(t.id)}
          >
            {/* ── Colour preview swatch ──────────────────────────────── */}
            <div
              aria-hidden="true"
              className="relative overflow-hidden rounded-lg"
              style={{ height: 60, background: c.background }}
            >
              {/* Sidebar strip (left edge) */}
              <div
                className="absolute inset-y-0 left-0 w-7"
                style={{ background: c.sidebarBackground }}
              />

              {/* Status bar strip (bottom edge) */}
              <div
                className="absolute inset-x-0 bottom-0 h-2"
                style={{ background: c.statusbarBackground }}
              />

              {/* Primary accent bar (simulates a tab / active file) */}
              <div
                className="absolute top-2.5 left-9 h-2 w-10 rounded-sm"
                style={{ background: c.primary }}
              />

              {/* "Content" lines — muted foreground at reduced opacity */}
              <div
                className="absolute top-[22px] left-9 h-1.5 w-14 rounded-sm"
                style={{ background: c.mutedForeground, opacity: 0.4 }}
              />
              <div
                className="absolute top-8 left-9 h-1.5 w-9 rounded-sm"
                style={{ background: c.mutedForeground, opacity: 0.25 }}
              />
            </div>

            {/* ── Label row ──────────────────────────────────────────── */}
            <div className="flex items-start justify-between gap-2">
              <div className="min-w-0">
                <p className="text-sm font-medium text-foreground">{t.label}</p>
                <p className="text-xs text-muted-foreground">{t.description}</p>
              </div>

              {selected ? (
                <span className="mt-0.5 shrink-0 rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                  Selected
                </span>
              ) : null}
            </div>
          </button>
        );
      })}
    </div>
  );
}

